INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00346', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「在滑世代中，觀看電影比以往更容易，除了走進電影院外，還有許多影 音串流平臺，隨時可以跟世界接軌。雖然觀看管道變多，但不變的是那種 大家一起待在共同空間中，同看一部電影的『儀式感』。隨著電影情節的 高低起伏，我們一起經歷冒險、體驗苦難，最後一同成長，這種一起笑、 一起哭、一起驚呼、一起療癒的過程，雖然每個人都是獨立的個體，卻不 再感到寂寞。」 根據上文，作者認為一起看電影的「儀式感」最可能的意義在於：', '["讓滑世代的孩子從網路世界抽離，面對現實考驗", "透過共同的觀看經驗，可形成記憶與話題的連結", "善於運用影音串流平臺的便利，以豐富娛樂生活", "集體觀看以刺激實體影音消費，促進影視的發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00347', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「美國科幻小說家雷‧布萊得伯利建議我們：既要學習接納別人的排斥， 也要學習排斥別人的接納。布萊得伯利的話嚴厲但實在，教我們以一種正 確的態度面對評論。當追求掌聲變成一種欲望，創作動機自然就變成對掌 聲的追求，這對作品可能是一種傷害。有些人對我們說好話，不見得是因 為作品，還有其他複雜的理由，例如人情關係等等；內行人對作品發表意 見，也有各種理由，未必著眼於作品，而更在反應這位內行人的其他思維。 我們要拿出自己的『測謊器』，辨識那些評論對我們是有幫助的。我們經 常忽略：批評最嚴厲的人，其實是我們的恩人；說最多好話的人，可能在 無形中害了我們。」 根據上文，下列選項何者最符合文意？', '["沒有評論不含複雜動機", "各種評論都應虛心採信", "讚美的背後必藏著毒藥", "迎合眾人可能扭曲創作"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00348', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '承上題，下列何者最符合上文對「內行人」的觀察？', '["有可能藉別人的作品談其他想法", "有時會為追求掌聲而褒揚創作者", "往往毫不留情面地嚴厲批評作品", "常自詡專業而不接納別人的排斥"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00349', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「有一家醫院為提升服務品質，改善對病人的醫療照護，請國際知名顧問 公司來幫忙。管理顧問提出各種炫目的流程圖與昂貴的資訊系統方案。後 來，這家醫院又找了另一家設計顧問公司來評估。這家設計人員將錄影機 架在自己頭上，躺在床上模擬病人錄下一天所看到的世界。設計公司發現， 病人一天中，一半以上的時間看不到『人類』，只看到天花板。他們唯一 能看到人的時候，是護士用輪椅帶他們去進行各種檢驗。所以，要如何改 善對病人的服務？醫師與護士看完影片後，決定不導入昂貴的資訊系統。 他們先布置天花板，用色彩繽紛的圖畫點綴，也在入口處放一個大白板， 讓探病的人留言。然後，他們在輪椅上裝一個照後鏡，讓病人可以在行進 中、說話時看到護士的臉，就這麼提升了服務品質。」 第二間顧問公司獲選的最主要原因是：', '["能同時滿足醫護人員與病人的多方需求", "能用更有創意的方法，提升管理的成效", "能理解醫院想節省經費解決問題的心理", "能從病人的角度發現問題，並找到解方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00350', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '承上題，醫院改善服務品質的方式，不包括下列何者？', '["增加檢驗的次數讓病人更安心", "讓探病的人在入口白板上留言", "輪椅裝照後鏡增加與人的互動", "醫護人員花費心力布置天花板"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00351', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲列乙為被告向民事法院起訴，乙抗辯該事件為行政爭訟事件而無審判 權，下列敘述何者錯誤？', '["受訴之民事法院認其有審判權而為裁判經確定時，關於審判權之判斷， 行政法院不受拘束", "甲、乙間就民事法院有無受理訴訟之權限有爭執者，民事法院應先為裁定", "受訴之民事法院認其無受理訴訟之權限時，應依職權裁定將此訴訟移送 至有受理訴訟權限之管轄法院", "如甲已就同一事件先向行政法院起訴，本件民事訴訟之起訴為不合法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00352', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '選定人得限制被選定人之訴訟行為，下列何者不包括在內？', '["捨棄", "和解", "撤回", "自認"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00353', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', 'A、B、C、D均為甲之繼承人，尚未為遺產分割，甲遺有某公寓之5樓房 屋，乙為該公寓 6 樓房屋之屋主，A、B 主張，因乙疏於維護 6 樓，致 5 樓房屋發生漏水損害，依民法第184條第1項前段規定向臺灣臺北地方法 院（下稱臺北地院）起訴請求乙負侵權行為損害賠償責任，A、B 並聲請 臺北地院裁定命C、D於收受裁定之日起7日內追加為原告。下列敘述何 者正確？', '["如C拒絕為原告，D所在不明，未追加為原告，臺北地院得以當事人不 適格為由駁回A、B之訴", "臺北地院裁定命C、D追加為原告，C、D不得抗告", "臺北地院裁定命C、D追加為原告，然C、D於第一次言詞辯論期日前 陳明拒絕同為原告之正當理由，臺北地院得撤銷原裁定", "臺北地院裁定命C、D追加為原告前，因本件損害賠償債權為對A、B、 C、D必須合一確定，臺北地院無庸命C、D陳述意見，即得為追加C、 D為原告之裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00354', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列訴訟，何者為意定訴訟擔當？', '["債權人甲代位行使其債務人之權利而提起訴訟", "多數有共同利益之人選定其中之甲為全體起訴", "遺產管理人為保存遺產而提起訴訟", "破產管理人為應收歸破產財團之財產而提起訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00355', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲向臺灣新北地方法院（下稱新北地院）對乙起訴請求返還借款新臺幣500 萬元，同時聲請新北地院准予訴訟救助獲准，下列何種程序並非該訴訟救 助效力所及？', '["上訴第二審", "抗告", "上訴第三審", "提起再審之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
